insert into public.keynotes (
  id, keynote_title, keynote_summary, image_url, image_alt, is_active, theme, audience, language, subtitle, moderation, keynote_long, keynote_short, speaker
)
values
  ('wenn-der-betonmischer-tesla-faehrt-kuenstliche-intelligenz-und-die-naechste-bauw', 'Wenn der Betonmischer Tesla fährt', 'Auftragsflaute, Fachkräftemangel und Bürokratie halten die Bauwirtschaft in Atem. Kann Künstliche Intelligenz das alles auf einmal lösen? Natürlich nicht! Unternehmer lösen ihre Probleme schon selber. Aber Christoph Holz zeigt drei Hebel, die heute schon Stückkosten, Kapitalbindung und Stehzeiten drücken — und fünf Gedankenexperimente fürs Übermorgen, die das Publikum selbst auswählt. Konkret, interaktiv, überraschend. Wer versteht wie, gewinnt.', 'placeholder', 'Wenn der Betonmischer Tesla fährt keynote image placeholder', true, 'Künstliche Intelligenz / Bauwirtschaft', 'Geschäftsführer, Vorstände und Führungskräfte aus Bauunternehmen, Baustoff- und Baumaschinenherstellern, Generalunternehmern und Bauträgern; Architekten und Planungsbüros; Verbände und Fachmedien der Bauwirtschaft. Geeignet für Strategie-Tagungen, Partner-Events, Jahreskonferenzen und Fachkongresse ab ca. 50 Personen.', 'Deutsch', 'Künstliche Intelligenz und die nächste Bauwirtschaft', 'Klar: Künstliche Intelligenz hat Auswirkungen. Aber welche eigentlich — ausgerechnet in einer Branche, die seit Jahrhunderten Stein auf Stein setzt? Prognosen scheitern an der Komplexität der Wirklichkeit. Gedankenexperimente sind anders. Sie spielen mit dem Möglichen. Was wäre, wenn der Bagger sich selbst steuert? Wenn die KI in Minuten plant, wofür ein Architekturbüro Wochen braucht? Wenn die Plattform den Generalunternehmer ablöst? Mit Christoph Holz — dem Informatiker, Raumfahrttechniker und Business Angel — schauen wir auf die Bauwirtschaft von morgen. Nicht ängstlich, sondern gestaltend. Viel Spaß!', '<p>Auftragsflaute, Fachkräftemangel, lähmende Bürokratie — und im Hintergrund teure Kredite und steigende Materialkosten. Die Bauwirtschaft kämpft 2026 an mehreren Fronten gleichzeitig. Jede einzelne Belastung wäre zu schaffen. Zusammen ergeben sie eine Kettenreaktion, die selbst gesunde Unternehmen ins Wanken bringt.</p><p><strong>Die provokante Frage:</strong> Kann Künstliche Intelligenz das wirklich alles auf einmal lösen — oder ist das nur das nächste Tech-Versprechen, das in der Branche verpufft?</p><p>Christoph Holz liefert die Antwort in zwei Teilen: heute schon funktionierende Hebel — und morgen denkbare Spielzüge. Beides interaktiv, beides mit dem Publikum.</p><h3>Teil 1 — Drei Hebel, die heute schon ziehen</h3><p><strong>1. Auftragsflaute &amp; schwache Nachfrage.</strong> KI senkt die Stückkosten am Bau — Projekte werden für Bauherren wieder kalkulierbar, die Nachfrage kommt zurück. Generative Planung liefert in Minuten hunderte bauphysikalisch geprüfte Grundriss-Varianten. Modulare Vorfertigung mit KI-Optimierung verkürzt Bauzeiten um bis zu 30 % und senkt Kosten um 15–20 %. Bid-Intelligence filtert aus öffentlichen Ausschreibungen die profitablen Projekte heraus — gleiche Vertriebsmannschaft, doppelte Pipeline-Qualität.</p><p><strong>2. Fachkräftemangel.</strong> KI als Force-Multiplier — vorhandene Fachkräfte schaffen das Zwei- bis Dreifache, Routine wandert an Maschinen. Autonome Bagger (Built Robotics, SafeAI) arbeiten im 24/7-Schichtbetrieb. 3D-Beton-Druck (ICON, COBOD) baut ein Einfamilienhaus mit drei Personen in 24 Stunden statt zwölf in sechs Wochen. KI-Co-Piloten erlauben Bauleitern, zwei bis drei Baustellen statt einer zu führen.</p><p><strong>3. Lähmende Bürokratie.</strong> Generative KI als Dokumentations- und Antrags-Roboter — was heute Tage dauert, geht in Minuten. KI-gestützte Bauanträge (dGRO, Approval AI) generieren komplette Unterlagen aus BIM-Modellen und prüfen gegen lokale Bauordnungen: aus 4–6 Wochen werden 2–4 Tage. Compliance-Tools markieren Mängel in Echtzeit. Bauleiter sparen 5–8 Stunden pro Woche, die heute in Formulare fließen.</p><p><em>Die entscheidende Einsicht: Die drei Belastungen verstärken sich gegenseitig — und KI ist das einzige Werkzeug, das an allen drei gleichzeitig ansetzt. Wer KI ignoriert, optimiert in einer Dimension und verliert in den anderen zwei.</em></p><h3>Teil 2 — Fünf Gedankenexperimente für übermorgen</h3><p>Interaktiv, vom Publikum gewählt. Christoph Holz spielt mit allen gemeinsam durch, was passiert, wenn man die heutigen Hebel konsequent weiterdenkt:</p><ol><li><strong>Der selbstplanende Hochbau:</strong> Was bleibt vom Architekten, wenn die KI in Minuten 200 Varianten liefert — und alle bauphysikalisch geprüft?</li><li><strong>Die selbstfahrende Baustelle:</strong> Wer haftet, wenn der autonome Bagger die Leitung trifft — und wer profitiert, wenn er sie nicht trifft?</li><li><strong>Generalunternehmer ohne Mitarbeiter:</strong> Können Plattformen wie Uber für Handwerker funktionieren — oder zerstören sie die Qualität, die das Geschäft ausmacht?</li><li><strong>Beton mit Algorithmus:</strong> Wann optimiert die KI Rezepturen schneller als jedes Materiallabor — und wem gehört das resultierende Patent?</li><li><strong>BIM zu Ende gedacht:</strong> Wenn jedes Bauteil weiß, was es ist und wo es hin will — brauchen wir dann noch Bauleiter?</li></ol><h3>Was die Keynote leistet</h3><p>Kein Technologie-Vortrag, kein Folienzwang, kein abstraktes Zukunftsblabla. Sondern ein Trainingslager für unternehmerisches Denken in einer Branche, deren Geschäftsmodelle gerade neu sortiert werden. Am Ende stehen keine Prognosen, sondern Optionen — und das Selbstvertrauen, sie zu gestalten.</p><p><strong>Wer versteht wie, gewinnt.</strong></p>', 'Auftragsflaute, Fachkräftemangel und Bürokratie halten die Bauwirtschaft in Atem. Kann Künstliche Intelligenz das alles auf einmal lösen? Natürlich nicht! Unternehmer lösen ihre Probleme schon selber. Aber Christoph Holz zeigt drei Hebel, die heute schon Stückkosten, Kapitalbindung und Stehzeiten drücken — und fünf Gedankenexperimente fürs Übermorgen, die das Publikum selbst auswählt. Konkret, interaktiv, überraschend. Wer versteht wie, gewinnt.', 'Christoph Holz, Dipl.-Informatiker und Raumfahrttechniker, ist Keynote Speaker, Hochschullehrer für Digitale Ethik und Business Angel. Als ehemaliger Silicon-Valley-Entrepreneur investiert er in Künstliche Intelligenz, Robotik und Blockchain von Australien bis Singapur. Sein Podcast „Digital Sensemaker" beleuchtet Sinn und Unsinn der Digitalisierung. Einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Auf der Bühne verbindet er Technologie, Gesellschaft und Wirtschaft mit Sprachwitz, eindrucksvollen Bildern und außergewöhnlichen Beispielen.'),
  ('pax-algorithmica-die-neue-weltordnung-der-ki', 'Pax Algorithmica — die neue Weltordnung der KI', 'Bleibt Europa Spielball einer fremden Weltordnung — oder gestalten wir mit? Wem nützt der Frieden, den die KI verspricht? Was können wir vom globalen Süden lernen, bevor wir zum Schwellenland absteigen?', 'placeholder', 'Pax Algorithmica — die neue Weltordnung der KI keynote image placeholder', true, 'Künstliche Intelligenz / Geopolitik / Werte & Ethik / Globaler Süden', 'Interessierte Öffentlichkeit; politische Stiftungen, Ministerien, Diplomatie, Public Affairs und Think Tanks; Vorstände, Geschäftsführungen, Strategie- und Innovations-Verantwortliche; Wirtschaftsverbände, Industrie- und Handelskammern, CEO-Foren; Universitäten und Volksbildung. Geeignet für öffentliche Abendveranstaltungen, politische Foren, Strategie-Klausuren, Wirtschaftskongresse und internationale Konferenzen mit geopolitischem Schwerpunkt.', 'Deutsch', 'Die neuen digitalen Supermächte zwischen Silicon Valley, Peking und dem Globalen Süden', 'Die Welt ordnet sich gerade neu. Aber wie eigentlich? Wird sie unfreier? Friedlicher? Vielfältiger? Oder vielleicht ganz anders, als wir denken?

Antworten — und Gegenfragen. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker" trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Lebt mein Unternehmen in einer Pax, deren Bedingungen andere diktieren — oder gestalten wir mit, was uns alle umgibt? Das fragt sich gerade jede Geschäftsleitung, die sich zwischen amerikanischen, chinesischen und Open-Source-Modellen entscheiden muss und dabei merkt, dass jede Wahl auch geopolitisch ist. Die gute Nachricht: Wir leben in der ersten Welt, in der Angriffskrieg ökonomisch unbezahlbar wird, in der Künstliche Intelligenz so billig wird wie Strom — und in der der Globale Süden zum ersten Mal seine eigenen Rohstoffe veredelt. Rom nannte das Pax Romana. Heute heißt sie anders.</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, dass der Frieden, den sie schafft, mehr als nur denen nützt, die sie bauen?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die die neue Weltordnung der KI neu vermessen — entgegen dem pessimistischen Alltagsbrei, der gerade in jeder zweiten Konferenz vibriert.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>Pax durch Verteidigungsdominanz.</strong> Satellitenaufklärung, Drohnen und KI haben den Angriffskrieg ökonomisch unbezahlbar gemacht. Erstmals in der Geschichte schlägt Verteidigung den Angriff systematisch. Was bedeutet das für eine Welt, in der die Frontlinie teurer wird als die Heimat, die sie verteidigt — und für unsere geopolitischen Reflexe, die das noch nicht begriffen haben?</li><li><strong>KI aus der Steckdose.</strong> Chinesische Anbieter beweisen schon heute: Künstliche Intelligenz wird Commodity wie Wasser, Strom, Kanalisation — Basisgebühr, jedem Haus verfügbar. Was passiert mit der Wertschöpfung, wenn die Intelligenz selbst billig wird? Und was bedeutet es, dass die Werte, die da aus dem Hahn kommen, irgendwo entwickelt wurden — nur nicht bei uns?</li><li><strong>Das Ende der Skalierung.</strong> Die Trainingsdaten gehen aus. Die nächste Modellgeneration kommt nicht so wie die letzte. Entlastet diese Stagnation die geopolitische Lage — oder zementiert sie die Position derer, die schon jetzt vorne sind? Und welche Strategie folgt aus einer Welt, in der KI nicht mehr jedes Jahr exponentiell besser wird, sondern endlich aufhört, ein Versprechen zu sein?</li><li><strong>Der Aufstieg des Südens.</strong> In Nigeria entstehen Unicorns, in Kenia entstehen Sprachmodelle für Suaheli, in Indien entscheiden 1,4 Milliarden Menschen, wessen KI sie nutzen. Afrika veredelt zum ersten Mal seine eigenen Rohstoffe — mit KI als Hebel — und wird zur neuen Wirtschaftsmacht. Was bedeutet das für unsere Märkte, unsere Lieferketten, unseren Reflex, den Süden als Zukunftsabnehmer alter Modelle zu sehen?</li><li><strong>Taiwan, die Lichtblende.</strong> TSMC ist nicht das nukleare Patt — es ist die Bühne, auf der USA und China sich gegenseitig in Schach halten. Im Windschatten dieser Stasis bekommt der Globale Süden die Zeit, die er braucht, um aufzuholen. Ist das die eigentliche Friedensgarantie der nächsten Dekade — oder nur eine Gnadenfrist, deren Ende wir aktiv mitgestalten müssen?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede Geschäftsleitung, jeder Vorstand und jedes Strategie-Komitee sich gerade stellen muss, wenn die nächste KI-Entscheidung längst auch eine geopolitische ist. Und das Selbstvertrauen, sie als Chance zu sehen — nicht als Drohung.</p><p>Was Europa beitragen kann, ist nicht der erhobene Zeigefinger des ethischen Architekten. Was Europa beitragen kann, ist Vorbildwirkung: KI so einzusetzen, dass es Schule macht. <strong>Vorbild statt Belehrung. Das ist Ethik.</strong></p><p><strong>In welchem Frieden wollen wir leben — in dem, der von Algorithmen anderer garantiert wird, oder in dem, den wir selbst mitgestalten?</strong></p>', 'Bleibt Europa Spielball einer fremden Weltordnung — oder gestalten wir mit? Wem nützt der Frieden, den die KI verspricht? Was können wir vom globalen Süden lernen, bevor wir zum Schwellenland absteigen?', 'Als interessierter Weltbürger hat Christoph Holz digitale Bildung in Armenien kennengelernt, Fintech-Unternehmen in Nigeria besucht, in China unknackbare Quantenkommunikation analysiert und bei München eine Kamikaze-Drohne montiert. Seine unternehmerische Reise brachte ihn bis ins Silicon Valley; heute investiert er in Start-ups von Dubai über Singapur bis Australien. An der Hochschule lehrt er Digitale Ethik und sortiert in seinem Podcast „Digital Sensemaker“ Sinn und Unsinn der Digitalisierung. Einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Dass er nebenbei Cyborg und Raumfahrttechniker ist, erklärt vielleicht, warum er die KI lieber aus der Umlaufbahn betrachtet — von dort, wo die Grenzen kleiner wirken als in den Nachrichten.'),
  ('was-robinson-crusoe-ueber-das-homeoffice-wusste', 'Was Robinson Crusoe über das Homeoffice wusste', 'Haben wir das Homeoffice eingeführt, um Kosten zu sparen — oder um endlich anders zu führen? Ist es zu viel verlangt von KI, dass sie unsere Organisation zusammenhält, wenn niemand mehr im Büro sitzt? Robinson hat seine Insel auch erst neu organisieren müssen.', 'placeholder', 'Was Robinson Crusoe über das Homeoffice wusste keynote image placeholder', true, 'Künstliche Intelligenz / New Work / Homeoffice / Robinson Crusoe', 'Geschäftsführungen, Vorstände, CEOs, COOs, CIOs und CHROs; HR- und People-Ops-Leitungen; Organisationsentwicklung und Transformations-Verantwortliche; Real-Estate- und Workplace-Strategie; Familienunternehmen, Mittelstand und Konzerne; Arbeitgeberverbände und Branchen-Organisationen. Geeignet für CEO-Foren, HR-Kongresse, Strategie-Klausuren, Vorstands-Off-Sites und Verbands-Tagungen mit Schwerpunkt Arbeitswelt und Organisation.', 'Deutsch', 'Perspektiven für Organisationen, wenn das Büro nicht mehr der Mittelpunkt ist', 'Homeoffice hat alles verändert. Aber was eigentlich? Sind unsere Teams produktiver? Loyaler? Oder einfach nur weiter weg? Und was wird aus unserer Kultur, wenn das Büro nur noch ein optionales Möbel ist?

Antworten — und Gegenfragen. Und ein Blick zurück zu Robinson Crusoe. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker" trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Haben wir das Homeoffice eingeführt, um Kosten zu sparen — oder um endlich anders zu führen? Das fragt sich gerade jede Geschäftsleitung, deren Bürofläche zu groß, deren Kultur zu dünn und deren KI-Roadmap zu ehrgeizig geworden ist. Die Pandemie war der Schiffbruch. Was übrig blieb, sind verstreute Inseln — und die Frage, was die Firma darauf eigentlich neu bauen soll.</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, dass sie unsere Organisation zusammenhält, wenn das Büro nicht mehr der Mittelpunkt ist — und uns dabei zwingt, neu zu denken, was „Firma" überhaupt bedeutet?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die die Robinson-Frage jeder modernen Organisation neu vermessen.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>Der Schiffbruch im Großraumbüro.</strong> Die Pandemie hat unser altes Organigramm verschluckt. Bauen wir die Firma auf der neuen Insel im alten Stil wieder auf — oder etwas, das tatsächlich für Inseln gebaut ist? Und wer entscheidet das: das Top-Management, HR, der Markt — oder die Mitarbeitenden, die längst abgestimmt haben?</li><li><strong>Wer beobachtet eigentlich, was passiert?</strong> Crusoe hatte den Strand vor Augen. Wir haben Dashboards, Engagement-Scores, Sentiment-Heatmaps. Sehen wir damit wirklich, was unsere Leute auf ihren Inseln machen — oder nur, was sich messen lässt? Und was, wenn die wichtigsten Spuren genau die sind, die kein KPI erfasst?</li><li><strong>Freitag, der KI-Mitarbeiter.</strong> Die KI ist der erste „Kollege", der nie krank wird, nie kündigt, nie eskaliert. Wie verändert das Personalplanung, Recruiting, Vergütung, Kultur — wenn die Hälfte der Arbeit von Werkzeugen erledigt wird, die niemand einstellt und niemand entlässt?</li><li><strong>Das Lagerfeuer am Strand.</strong> Crusoe brauchte das Feuer, um nicht zu erfrieren — und um gesehen zu werden. Was ist das Lagerfeuer unserer Firma, wenn alle auf eigenen Inseln sitzen? Brand, Mission, gemeinsame Rituale, Off-Sites? Was hält uns zusammen, wenn der Bürotag wegfällt — und was kostet das?</li><li><strong>Das Rettungsschiff am Horizont.</strong> Sollen wir die Leute „zurück ins Büro" holen, weil wir uns nach dem alten Schiff sehnen — oder akzeptieren wir, dass die Inseln die neue Welt sind, und richten die Organisation darauf ein? Wer entscheidet das wirklich: die Kostenrechnung, die Kultur, oder das, was die besten Talente noch akzeptieren?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede Geschäftsleitung, jede HR-Strategie und jede Organisationsentwicklung sich gerade stellen muss. Und das Selbstvertrauen, die eigene Insel neu zu bauen — statt auf das Schiff zu warten, das nicht mehr kommt.</p><p><strong>Haben wir das Homeoffice eingeführt, um Kosten zu sparen — oder um endlich anders zu führen?</strong></p>', 'Haben wir das Homeoffice eingeführt, um Kosten zu sparen — oder um endlich anders zu führen? Ist es zu viel verlangt von KI, dass sie unsere Organisation zusammenhält, wenn niemand mehr im Büro sitzt? Robinson hat seine Insel auch erst neu organisieren müssen.', 'Christoph Holz hat in seiner Firma Homeoffice eingeführt, als es noch Telearbeit hieß. Schon damals war ihm klar, dass die besten Ideen selten im Großraumbüro entstehen. Aus dem Silicon Valley brachte er die Erfahrung mit, dass Eigenverantwortung mehr leistet als Anwesenheitspflicht. Heute investiert er als Business Angel in Quantencomputer und Künstliche Intelligenz und lehrt als Hochschullehrer Digitale Ethik. In seinem Podcast „Digital Sensemaker“ trennt er Sinn und Unsinn der Digitalisierung; einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Dass er nebenbei Cyborg und Raumfahrttechniker ist, erklärt vielleicht, warum er die Insel des Homeoffice lieber selbst gestaltet, als auf das Rettungsschiff zu warten.'),
  ('wenn-der-op-roboter-zweimal-klingelt', 'Das selbstfahrende Krankenhaus', 'Bin ich Arzt geworden, um mit einer Software um die bessere Diagnose zu konkurrieren — oder um Menschen zu heilen? Ist es zu viel verlangt von KI, dass sie der Medizin die Routine abnimmt und ihr zurückgibt, was sie zur Berufung gemacht hat?', 'images/das-selbstfahrende-krankenhaus.jpg', 'Das selbstfahrende Krankenhaus keynote image placeholder', true, 'Künstliche Intelligenz / Gesundheit & Medizin', 'Ärztinnen und Ärzte aller Disziplinen; Chefärzte, ärztliche Direktoren und Klinikvorstände; Verwaltungs- und Geschäftsführungen von Krankenhäusern; Ärztekammern, medizinische Fachgesellschaften, Hochschulmedizin und Forschungsinstitutionen; Health-Tech-Unternehmen und Klinik-IT-Verantwortliche. Geeignet für medizinische Kongresse, Klinik-Tagungen, Fachärzte-Fortbildungen und Strategie-Workshops von Krankenhausträgern.', 'Deutsch', 'Gedankenexperimente zur Zukunft der ärztlichen Arbeit', 'Künstliche Intelligenz hat Auswirkungen für die Medizin. Aber welche eigentlich? Die guten? Die unheimlichen? Die, über die noch niemand redet?

Antworten — und Gegenfragen. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker" trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Bin ich Arzt geworden, um mit einer Software um die bessere Diagnose zu konkurrieren — oder um Menschen zu heilen? Das fragt sich derzeit jede Generation in Weiß. Diagnose-KI liest Mammographien zuverlässiger als jeder Radiologe. Der OP-Roboter hält ruhiger als jede menschliche Hand. Predictive Health weiß, was wir bekommen werden, bevor wir es bekommen. Wird ärztliche Arbeit damit überflüssig — oder bekommt sie endlich die Zeit zurück, die ihr immer gefehlt hat?</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, wenn wir uns erwarten, dass sie uns die Würde der ärztlichen Arbeit wieder zurückgibt?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die das Selbstverständnis des Arztberufs neu vermessen.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>Die Diagnose als Geschenk.</strong> Wenn die KI in dreißig Sekunden findet, wofür der Arzt drei Sprechstunden gebraucht hätte — bekommt die Ärztin dann endlich Zeit für das Gespräch zurück, oder wird die Sprechstunde auf fünf Minuten getaktet? Wer entscheidet darüber: die Patient:innen, die Klinik, der Algorithmus?</li><li><strong>Wer haftet, wenn der Roboter schneidet?</strong> Der OP-Roboter operiert ruhiger und präziser als jeder Mensch. Der Patient unterschreibt die Einwilligung — aber bei wem? Beim Chirurgen, der den Knopf drückt? Beim Hersteller, der die Software liefert? Bei der Klinik, die den Eingriff verantwortet? Oder bei der KI selbst — und falls ja, was bedeutet das für die ärztliche Autonomie?</li><li><strong>Der KI-Therapeut.</strong> Ein Chatbot ist 24/7 verfügbar, urteilt nicht, vergisst nichts und erinnert sich an jedes Detail. In der Psychotherapie und Psychiatrie zeichnet sich ab: Patient:innen öffnen sich der KI oft schneller als einem Menschen. Heilt sie — oder verlieren wir genau das, was Heilung erst möglich macht?</li><li><strong>Vorhersage statt Heilung.</strong> Die KI kennt deine Erkrankung Jahre, bevor du sie hast. Will der Patient das überhaupt wissen? Hat seine Versicherung ein Recht darauf? Und was, wenn die Vorhersage zur sich selbst erfüllenden Prophezeiung wird — weil der Mensch sein Leben fortan im Schatten einer Diagnose führt, die noch gar nicht eingetreten ist?</li><li><strong>Der zweite Blick.</strong> Wenn die KI jede ärztliche Entscheidung gegenprüft und Abweichungen meldet — befreit das den Arzt vom Risiko, oder degradiert es ihn zum Ausführungsorgan eines Algorithmus? Was wird aus der ärztlichen Intuition, wenn sie statistisch widerlegt werden kann?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede Klinikführung, jede Praxis und jede medizinische Fakultät sich gerade stellen muss. Und das Selbstvertrauen, sie zu gestalten.</p><p><strong>Bin ich Arzt geworden, um mit einer Software um die bessere Diagnose zu konkurrieren — oder um Menschen zu heilen?</strong></p>', 'Bin ich Arzt geworden, um mit einer Software um die bessere Diagnose zu konkurrieren — oder um Menschen zu heilen? Ist es zu viel verlangt von KI, dass sie der Medizin die Routine abnimmt und ihr zurückgibt, was sie zur Berufung gemacht hat?', 'Christoph Holz, Dipl.-Informatiker und Raumfahrttechniker, ist Hochschullehrer für Digitale Ethik und hat am Standesamt in Medizin promoviert. Seine Frau ist nämlich Anästhesistin, Palliativmedizinerin und Ethikberaterin. Als ehemaliger Silicon-Valley-Entrepreneur investiert er in Quantencomputer und Künstliche Intelligenz. Sein Podcast „Digital Sensemaker" trennt Sinn und Unsinn der Digitalisierung. Einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Auf der Bühne verbindet er Technologie, Gesellschaft und Wirtschaft mit Sprachwitz, eindrucksvollen Bildern und außergewöhnlichen Beispielen.'),
  ('mein-gesunder-zwilling', 'Länger gesund mit Smartwatch, KI und Hausverstand', 'Will ich wissen, woran ich sterbe — oder wie ich leben will? Ist es zu viel verlangt von KI, dass sie uns die Sorge ums Krankwerden abnimmt und uns zurückgibt, was Gesundsein eigentlich bedeutet?', 'placeholder', 'Länger gesund mit Smartwatch, KI und Hausverstand keynote image placeholder', true, 'Künstliche Intelligenz / Gesundheit & Selbstbestimmung', 'Privatpersonen, die gesund werden und bleiben wollen; gesundheitsbewusste Erwachsene aller Altersgruppen; Patient:innen und Patientenverbände; Selbsthilfegruppen; Volkshochschulen und Erwachsenenbildung; Apotheken-Kund:innenveranstaltungen; Krankenkassen-Events für Versicherte; Gesundheitsmessen und Publikumskongresse; Reha-Zentren und Vorsorge-Einrichtungen. Geeignet für öffentliche Abendvorträge, Mitgliederversammlungen, Gesundheitstage und kuratierte Talkreihen.', 'Deutsch', 'Gedankenexperimente, was Algorithmen für Ihre Gesundheit können — und was Sie selbst entscheiden müssen', 'Künstliche Intelligenz mischt sich in Ihre Gesundheit ein. Aber wie eigentlich? Hilft sie? Überwacht sie? Entscheidet sie?

Antworten — und Gegenfragen. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker" trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Will ich wissen, woran ich sterbe — oder wie ich leben will? Das fragen sich gerade Millionen Menschen, die ihre Schritte zählen, ihren Schlaf vermessen, ihren Puls überwachen lassen. Eine App liest Symptome zuverlässiger als der Hausarzt am Mittwoch um halb sechs. Das Wearable weiß, dass ich krank werde, bevor ich es spüre. Der digitale Zwilling probiert Medikamente an einer Kopie von mir durch, bevor ich sie schlucke. Wird Gesundheit damit besser — oder verlieren wir das Lebensgefühl, das wir damit eigentlich schützen wollten?</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, dass sie uns die Sorge ums Krankwerden abnimmt und uns zurückgibt, was Gesundsein eigentlich bedeutet?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die das eigene Verhältnis zu Gesundheit, Körper und Daten neu vermessen.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>Der KI-Arzt in der Hosentasche.</strong> Eine App liest meine Symptome besser als die Hausärztin am Mittwoch um halb sechs. Kein Wartezimmer, keine Termine, keine Notaufnahme. Spart mir das Zeit und Nerven — oder spart es vor allem das Gesundheitssystem, das mich nun erst sehen will, wenn die KI grünes Licht gibt?</li><li><strong>Die Diagnose vor der Diagnose.</strong> Mein Wearable kennt meinen Herzinfarkt zwei Jahre, bevor er passiert. Will ich das überhaupt wissen? Was macht es mit einem Leben, wenn man es im Schatten einer Diagnose führt, die noch gar nicht eingetreten ist? Und wer darf außer mir mitlesen — Hausarzt, Versicherung, Arbeitgeber?</li><li><strong>Mein digitaler Zwilling.</strong> Eine vollständige Kopie meines Körpers, an der die KI Medikamente und Therapien durchprobiert, bevor sie bei mir landen. Wem gehört dieser Zwilling — mir, dem Hersteller, der Krankenkasse? Und wenn der Zwilling stirbt: zählt das als Datenpunkt oder als Warnung?</li><li><strong>Der KI-Coach für ein langes Leben.</strong> Schlaf, Bewegung, Ernährung, Stress — die KI weiß, was mir gut tut, besser als ich selbst. Werde ich gesünder, weil mir endlich jemand zuhört — oder verliere ich die Souveränität über das eine Leben, das ich habe?</li><li><strong>Gesundheit als Score.</strong> Versicherungsbeitrag, Mietvertrag, Job-Angebot hängen am persönlichen Health-Score. Belohnt das gesundes Verhalten — oder bestraft es alle, deren Gesundheit ihnen nicht freisteht? Und wo verläuft die Grenze zwischen Prävention und stiller Disziplinierung?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede und jeder von uns sich gerade stellen muss, wenn das Smartphone zum Hausarzt und das Armband zum Lebenscoach wird. Und das Selbstvertrauen, eigene Antworten zu finden.</p><p><strong>Will ich wissen, woran ich sterbe — oder wie ich leben will?</strong></p>', 'Will ich wissen, woran ich sterbe — oder wie ich leben will? Ist es zu viel verlangt von KI, dass sie uns die Sorge ums Krankwerden abnimmt und uns zurückgibt, was Gesundsein eigentlich bedeutet?', 'Christoph Holz, Dipl.-Informatiker und Raumfahrttechniker, ist Hochschullehrer für Digitale Ethik und hat am Standesamt promoviert. Seine Frau ist nämlich Anästhesistin, Palliativmedizinerin und Ethikberaterin. Als ehemaliger Silicon-Valley-Entrepreneur investiert er in Quantencomputer und Künstliche Intelligenz. Sein Podcast „Digital Sensemaker" trennt Sinn und Unsinn der Digitalisierung. Einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Auf der Bühne verbindet er Technologie, Gesellschaft und Wirtschaft mit Sprachwitz, eindrucksvollen Bildern und außergewöhnlichen Beispielen.'),
  ('was-wir-von-pippi-langstrumpf-ueber-new-work-lernen-koennen', 'Was wir von Pippi Langstrumpf über New Work lernen können', 'Bin ich arbeiten gegangen, um zu funktionieren — oder um mir die Welt zu machen, widewide wie sie mir gefällt? Ist es zu viel verlangt von KI, dass sie uns die Mühsal abnimmt und uns zurückgibt, was Arbeit eigentlich sein darf: persönliches Wachstum, Sinn und Menschlichkeit?', 'placeholder', 'Was wir von Pippi Langstrumpf über New Work lernen können keynote image placeholder', true, 'Künstliche Intelligenz / New Work / Selbstbestimmung / Pippi Langstrumpf', 'Arbeitnehmer:innen aller Branchen; Knowledge Worker und Wissensarbeitende; Solopreneure, Freelancer und Gig Worker; HR und People-Ops; Berufseinsteiger:innen und Generation Z; New-Work-Communities und Coworking-Spaces; Betriebsräte und gewerkschaftliche Bildungsarbeit; Mitarbeitendenveranstaltungen, Belegschaftsversammlungen, Inhouse-Tagungen. Geeignet für Mitarbeiter:innen-Events, New-Work-Konferenzen, HR-Strategie-Klausuren und Generations-Dialoge.', 'Deutsch', 'Perspektiven für eine Arbeit, widewide wie sie uns gefällt', 'Arbeit verändert sich. Aber wie eigentlich? Wird sie freier? Verrückter? Anstrengender? Oder einfach nur unübersichtlicher?

Antworten — und Gegenfragen. Und ein Blick zurück zur stärksten Sechsjährigen der Weltliteratur. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker" trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Bin ich arbeiten gegangen, um zu funktionieren — oder um mir die Welt zu machen, widewide wie sie mir gefällt? Das fragt sich gerade jede Generation, deren KI mehr kann als ihr Chef, deren Arbeitsplatz ein Café in Lissabon sein darf und deren Karriereplan auf einer Serviette steht. Pippi Langstrumpf hat das längst beantwortet: Wer sich die Welt nicht selbst macht, dem macht sie jemand anders.</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, dass sie uns die Pflicht abnimmt — und uns zurückgibt, was Arbeit eigentlich sein darf: ein eigenes Abenteuer?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die die Villa Kunterbunt der neuen Arbeitswelt neu vermessen.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>„Das hab ich noch nie probiert, also bin ich völlig sicher, dass ich es kann."</strong> Pippis Mantra. Mit KI an der Seite traut sich jede:r zu, was er oder sie nie konnte: programmieren, illustrieren, verhandeln, ein Buch schreiben. Werden wir damit mutiger — oder bilden wir uns nur Kompetenz ein, die wir gar nicht haben?</li><li><strong>Die Villa Kunterbunt.</strong> Pippi richtet sich Arbeits- und Lebensraum selbst ein, ohne Erlaubnis. Workation, Coliving, eigene Werkstatt: Was passiert, wenn „Arbeitsplatz" zur reinen Wahl-Entscheidung wird — und mit ihm die Identität, die wir bisher daraus gezogen haben?</li><li><strong>Pippi hebt das Pferd hoch.</strong> Was Pippi mit der Hand schafft, schaffen wir mit der KI. Plötzlich kann jede einzelne Person das Zehnfache leisten. Werden wir damit zu Pippi — oder werden wir zu Annika daneben, die staunt und nichts mehr beizutragen weiß?</li><li><strong>Mr. Nilsson, der unberechenbare Assistent.</strong> Pippis Äffchen klaut, kichert, macht Unfug. KIs auch. Was machen wir, wenn unsere Werkzeuge nicht tun, was wir wollen, sondern was sie für richtig halten — und das Ergebnis trotzdem oft das bessere ist?</li><li><strong>Annika und Tommy gehen nach Hause.</strong> Pippis Freunde fanden ihr Leben aufregend, aber abends gingen sie heim ins Bett zu den Eltern. Wer sind wir eigentlich: die freie Pippi — oder die Annikas und Tommys, die das Pippi-Leben gern aus sicherer Entfernung beobachten?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede:r selbst beantworten muss, der oder die heute morgen ins Büro, in die Küche oder ins Café gegangen ist, um zu arbeiten. Und das Selbstvertrauen, sich die eigene Villa Kunterbunt zu bauen.</p><p><strong>Bin ich arbeiten gegangen, um zu funktionieren — oder um mir die Welt zu machen, widewide wie sie mir gefällt?</strong></p>', 'Bin ich arbeiten gegangen, um zu funktionieren — oder um mir die Welt zu machen, widewide wie sie mir gefällt? Ist es zu viel verlangt von KI, dass sie uns die Mühsal abnimmt und uns zurückgibt, was Arbeit eigentlich sein darf: persönliches Wachstum, Sinn und Menschlichkeit?', 'Christoph Holz ist Vordenker und Pionier der Neuen Arbeit. Seit Jahrzehnten lebt er Eigenverantwortung und kooperative Strukturen in seinen Unternehmen. Aus dem Silicon Valley brachte er die Erfahrung mit, dass die besten Ideen selten am Schreibtisch entstehen. Heute investiert er als Business Angel in Quantencomputer und Künstliche Intelligenz und lehrt als Hochschullehrer Digitale Ethik. In seinem Podcast „Digital Sensemaker" trennt er Sinn und Unsinn der Digitalisierung; einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Dass er nebenbei Cyborg und Raumfahrttechniker ist, erklärt vielleicht, warum er von einer Arbeit träumt, in der jeder sich die Welt machen darf, widewide wie sie ihm gefällt.'),
  ('was-wir-von-winnetou-ueber-digitale-fuehrung-lernen-koennen', 'Digital Leadership — was wir von Winnetou lernen können', 'Bin ich Chef geworden, um Anweisungen zu geben — oder um Menschen zu führen? Ist es zu viel verlangt von KI, dass sie uns die Hierarchie abnimmt und der Führung zurückgibt, was sie eigentlich ausmacht? Die Apachen haben das immer schon gewusst.', 'placeholder', 'Digital Leadership — was wir von Winnetou lernen können keynote image placeholder', true, 'Digitale Führung / Winnetou', 'Führungskräfte aller Ebenen; Geschäftsführungen, Vorstände, Bereichs- und Teamleitungen; HR, Personalentwicklung und Leadership-Coaches; Transformations- und New-Work-Verantwortliche; Familienunternehmen und Mittelstand; Verbandstagungen und Strategie-Klausuren. Geeignet für Führungskräfte-Kongresse, Jahrestagungen, Leadership-Konferenzen und Off-Sites mit Inspirationscharakter.', 'Deutsch', 'Gedankenexperimente zur Führung im KI-Zeitalter', 'Künstliche Intelligenz verändert auch die Führung. Aber wie eigentlich? Übernimmt sie das Sagen? Macht sie Chefs überflüssig? Oder befreit sie endlich von dem, was nie Führung war?

Antworten — und Gegenfragen. Und ein Blick zurück zu Winnetou. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker" trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Bin ich Chef geworden, um Anweisungen zu geben — oder um Menschen zu führen? Das fragt sich gerade jede Generation, die im Großraumbüro KPIs jagt, im Homeoffice Vertrauen verteilt und im Meeting mit einer KI um die bessere Idee ringt. Die Apachen wussten es längst: Ihre Nant''ans hatten kein Befehlsrecht. Sie führten durch Vorbildwirkung — oder gar nicht.</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, dass sie uns die Hierarchie abnimmt und der Führung zurückgibt, was sie eigentlich ausmacht — Vorbildwirkung?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die das Selbstverständnis digitaler Führung neu vermessen — am Lagerfeuer, mit Winnetou.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>Der Häuptling ohne Befehlsrecht.</strong> Apache-Nant''ans führten, weil sie als Vorbild taugten — nicht, weil sie es durften. Was passiert mit der modernen Führungskraft, wenn jeder Mitarbeitende die KI als Zweitmeinung im Browser hat? Wer folgt dem Chef noch, wenn der Algorithmus widerspricht?</li><li><strong>Lagerfeuer statt Großraumbüro.</strong> Apachen lebten in Bands — kleine Einheiten, die sich bildeten und auflösten, wann es sinnvoll war. Ist das Homeoffice die späte Rückkehr zum Stammesprinzip? Oder verlieren wir das Lagerfeuer, an dem Vertrauen, Loyalität und Esprit überhaupt erst entstehen?</li><li><strong>Spuren lesen, nicht Dashboards.</strong> Winnetou erkannte einen Reiter an drei Hufabdrücken. Die Führungskraft heute liest KPIs, Sentiment-Scores, Engagement-Heatmaps. Was sehen wir damit besser — und was übersehen wir komplett, weil es sich nicht messen lässt?</li><li><strong>Die Friedenspfeife mit der KI.</strong> Konflikte wurden im Apache-Stamm im Kreis verhandelt, nicht von oben entschieden. Wenn die KI als neutrale Instanz vorschlägt, wie ein Streit „richtig" zu lösen wäre — wer hält dann die Friedenspfeife? Die Führungskraft, das Team, oder der Algorithmus, der nie persönlich betroffen ist?</li><li><strong>Manitou im Maschinenraum.</strong> Über jedem Häuptling stand eine höhere Instanz. Was, wenn die KI diese Instanz wird? Wenn jede Führungsentscheidung am Algorithmus gegengeprüft wird — befreit das die Führungskraft vom Risiko, oder degradiert sie zur Ausführenden eines übergeordneten Codes?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede Geschäftsführung, jede Personalleitung und jede Strategie-Klausur sich gerade stellen muss. Und das Selbstvertrauen, sie zu gestalten — am Lagerfeuer der digitalen Welt.</p><p><strong>Bin ich Chef geworden, um Anweisungen zu geben — oder um Menschen zu führen?</strong></p>', 'Bin ich Chef geworden, um Anweisungen zu geben — oder um Menschen zu führen? Ist es zu viel verlangt von KI, dass sie uns die Hierarchie abnimmt und der Führung zurückgibt, was sie eigentlich ausmacht? Die Apachen haben das immer schon gewusst.', 'Christoph Holz ist Vordenker und Pionier der Neuen Führung. Seit Jahrzehnten lebt er kooperative Führung und Eigenverantwortung in seinen Unternehmen. Aus dem Silicon Valley brachte er die Erfahrung mit, dass Hierarchie und Innovation einander selten vertragen. Heute investiert er als Business Angel in Quantencomputer und Künstliche Intelligenz und lehrt als Hochschullehrer Digitale Ethik. In seinem Podcast „Digital Sensemaker“ trennt er Sinn und Unsinn der Digitalisierung; einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Dass er nebenbei Cyborg und Raumfahrttechniker ist, erklärt vielleicht, warum er Führung lieber am Lagerfeuer denkt als am Organigramm.'),
  ('wenn-der-pflegeroboter-zweimal-klingelt', 'Wenn der Pflegeroboter zweimal klingelt', 'Bin ich Pflegeperson geworden, um Checklisten abzuarbeiten — oder um Menschen zu begleiten? Ist es zu viel verlangt von KI, dass sie der Pflege die Routine abnimmt und ihr zurückgibt, was sie zur Berufung gemacht hat?', 'placeholder', 'Wenn der Pflegeroboter zweimal klingelt keynote image placeholder', true, 'Künstliche Intelligenz / Pflege', 'Pflegende aller Ebenen — von der Stationspflege bis zur Pflegedienstleitung; Pflegedirektorinnen und Pflegedirektoren in Krankenhäusern; Heim- und Einrichtungsleitungen; Träger ambulanter Pflegedienste; Pflegekammern und Berufsverbände; Caritas, Diakonie, AWO und andere Wohlfahrtsverbände; Lehrkräfte und Schulleitungen in der Pflegepädagogik. Geeignet für Pflege-Kongresse, Träger-Tagungen, Führungskräfte-Workshops und Strategie-Klausuren in der Langzeitpflege.', 'Deutsch', 'Gedankenexperimente zur Zukunft der Pflege', 'Künstliche Intelligenz hat Auswirkungen für die Pflege. Aber welche eigentlich? Die guten? Die unheimlichen? Die, über die noch niemand redet?

Antworten — und Gegenfragen. Unser Vortragender ist Informatiker, Raumfahrttechniker und Cyborg. An der Hochschule unterrichtet er Digitale Ethik, privat investiert er in Quantencomputer und KI. In seinem Podcast „Digital Sensemaker“ trennt er Sinn von Unsinn der Digitalisierung — einer breiten Öffentlichkeit ist er als TV-Experte bekannt. Begrüßen Sie mit mir: Christoph Holz.', '<p>Bin ich Pflegeperson geworden, um Checklisten abzuhaken? Bin ich in die Pflege gegangen, um Pflegeroboter zu programmieren? Das fragt sich derzeit jede Generation, die rund um die Uhr Hände hält, Wunden versorgt und Trost spendet. Hebe-Roboter retten Bandscheiben. Ambient-Scribes nehmen die Dokumentation ab. Schichtplanungs-KI sortiert Personalmangel kreativ. Sturz-Sensoren warnen, bevor der Sturz passiert. Wird Pflege damit besser — oder verlieren Pflegekräfte genau das, wofür sie diesen Beruf gewählt haben?</p><p><strong>Die provokante Frage:</strong> Ist es zu viel verlangt von KI, wenn wir uns erwarten, dass sie uns die Würde der Pflegearbeit wieder zurückgibt?</p><p>Christoph Holz spielt mit dem Publikum fünf Gedankenexperimente durch, die das Selbstverständnis der Pflege neu vermessen.</p><h3>Fünf Gedankenexperimente</h3><ol><li><strong>Pflege als Beziehungsarbeit.</strong> Wenn die KI die Dokumentation übernimmt und Pflegekräften fünf bis acht Stunden pro Woche zurückgibt — bekommt die Pflege damit endlich Zeit für den Menschen, oder schlägt das Pendel um, und die Stationsleitung erwartet einfach 30 % mehr Patient:innen pro Schicht?</li><li><strong>Wer hält die Hand?</strong> Der Pflegeroboter hebt, dreht, mobilisiert. Er erkennt den Sturz, bevor er passiert. Aber kann er trösten? Sollte er es überhaupt versuchen — und wenn ja, wer entscheidet, wann der Mensch wieder übernehmen muss?</li><li><strong>Schichtplanung durch die KI.</strong> Eine KI errechnet die optimale Personalverteilung in Echtzeit, kennt die Belastbarkeit jeder Pflegekraft, prognostiziert Krankenstand. Befreit das die Stationsleitung vom Dauer-Stress des Improvisierens — oder werden Pflegende zur Manövriermasse eines Algorithmus, der niemals erschöpft ist?</li><li><strong>Patient:innen-Monitoring 24/7.</strong> Wearables, Sensoren, Kamera-KI sehen alles: den drohenden Sturz, den steigenden Blutdruck, die Verwirrung. Aber sehen sie auch die Tränen? Welche Rolle bleibt der Pflegekraft, wenn die Maschine immer früher Alarm schlägt als das geübte Auge?</li><li><strong>Pflegeausbildung im KI-Zeitalter.</strong> Was lernt die Schwester, der Pfleger von morgen? Wenn die KI Vitalparameter, Medikation und Wunddokumentation übernimmt — wofür wird die nächste Generation noch ausgebildet? Für die Maschine — oder für den Menschen?</li></ol><h3>Was die Keynote leistet</h3><p>Pure Gedankenexperimente, interaktiv vom Publikum gewählt — konkret, provozierend, mit Humor. Am Ende stehen nicht die Antworten, sondern die Fragen, die jede Pflegedienstleitung, jede Heimleitung und jede Pflegeschule sich gerade stellen muss. Und das Selbstvertrauen, sie zu gestalten.</p><p><strong>Bin ich Pflegeperson geworden, um Checklisten abzuhaken — oder um Menschen zu begleiten?</strong></p>', 'Bin ich Pflegeperson geworden, um Checklisten abzuarbeiten — oder um Menschen zu begleiten? Ist es zu viel verlangt von KI, dass sie der Pflege die Routine abnimmt und ihr zurückgibt, was sie zur Berufung gemacht hat?', 'Christoph Holz, Dipl.-Informatiker und Raumfahrttechniker, ist Hochschullehrer für Digitale Ethik und hat am Standesamt in Medizin promoviert. Seine Frau ist nämlich Anästhesistin, Palliativmedizinerin und Ethikberaterin. Als ehemaliger Silicon-Valley-Entrepreneur investiert er in Quantencomputer und Künstliche Intelligenz. Sein Podcast „Digital Sensemaker" trennt Sinn und Unsinn der Digitalisierung. Einer breiten Öffentlichkeit ist er als TV-Experte (Sat.1, RTL, n-tv) bekannt. Auf der Bühne verbindet er Technologie, Gesellschaft und Wirtschaft mit Sprachwitz, eindrucksvollen Bildern und außergewöhnlichen Beispielen.'),
  ('digitale-ethik-ist-unmoralisch', 'Digitale Ethik ist unmoralisch', 'Cyber War, Massenüberwachung, rassistische Algorithmen — die digitalen Schlagzeilen klingen, als stünde das Abendland kurz vor dem Aus. Stimmt das wirklich? Oder steht hinter den Aufregern eine Wirklichkeit, die ruhiger, ehrlicher und interessanter ist, als die Empörung uns glauben macht?

Sieben Spannungsfelder, jenseits der Skandalisierung. Ohne Verharmlosung, ohne Weltuntergang — praktische Ethik für ein Jahrhundert, das komplexer ist als seine Schlagzeilen.', 'images/digitale-ethik-ist-unmoralisch.jpg', 'Digitale Ethik ist unmoralisch keynote image placeholder', true, 'Digitale Ethik / Technologieethik in der Technologie', 'Interessierte Öffentlichkeit, die hinter die Schlagzeilen sehen will; Studierende aller Fachrichtungen, insbesondere Informatik, Wirtschaft, Philosophie, Rechts- und Politikwissenschaften; Unternehmer:innen, Geschäftsführungen, Innovations- und Strategie-Verantwortliche; Lehrkräfte und Multiplikatoren in der Erwachsenenbildung; politische Stiftungen, Kulturveranstalter, Buchclubs und Bildungsbürgertum. Geeignet für öffentliche Abendvorträge, Hochschul-Ringvorlesungen, Bildungsformate, Awards-Veranstaltungen und Wirtschaftsforen mit gesellschaftlichem Anspruch.', 'Deutsch', 'Die echten moralischen Herausforderungen einer Digitalen Ökonomie — jenseits der Skandalisierung', 'Klar: Digitale Technik hat Auswirkungen. Aber welche eigentlich? Prognosen scheitern an der Komplexität der Wirklichkeit. Gedankenspiele sind anders. Sie spielen mit dem Möglichen. Was wäre wenn? Wenn es keine Städte mehr gäbe - oder Firmen - oder Mitarbeiter? Mit Christoph Holz - dem Informatiker & Raumfahrttechniker betrachten wir die großen Herausforderungen der Menschheit - aus der Perspektive der Zukunft. Viel Spaß!', NULL, 'Cyber War, Massenüberwachung, rassistische Algorithmen — die digitalen Schlagzeilen klingen, als stünde das Abendland kurz vor dem Aus. Stimmt das wirklich? Oder steht hinter den Aufregern eine Wirklichkeit, die ruhiger, ehrlicher und interessanter ist, als die Empörung uns glauben macht?

Sieben Spannungsfelder, jenseits der Skandalisierung. Ohne Verharmlosung, ohne Weltuntergang — praktische Ethik für ein Jahrhundert, das komplexer ist als seine Schlagzeilen.', 'Christoph Holz erklärt die komplexe digitale Welt auf unvergleichliche und humorvolle Weise. Seine spannenden Gedankenexperimente zeigen den größeren Kontext und die ganz persönlichen Auswirkungen auf jeden Einzelnen. Der Informatiker und Raumfahrttechniker weiß, wovon er spricht. Er ist Start-up-Gründer, Silicon-Valley-Entrepreneur, Angel-Investor und ein echter Cyborg. Wie kaum ein anderer übersetzt er digitales Wissen in logische Zukunftsszenarien und überraschende Konsequenzen. Seine Tätigkeiten als Redner, Podcaster und Hochschullektor führten Holz von der CeBit und TEDx bis zu Google nach Kalifornien. Christoph Holz weiß mit Sprachwitz, eindrucksvollen Bildern und außergewöhnlichen Beispielen zu begeistern. Er verbindet Technologie, Gesellschaft und Wirtschaft zu einem sinnstiftenden Ganzen.')
